package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetPriceInMicros() throws Exception {
    String name = "Test Item";
    int quantity = 5;
    long priceInMicros = 123456789L;
    String currencyCode = "USD";

    // Use reflection to instantiate LineItem since constructor is not accessible
    Class<?> lineItemClass = Class.forName("com.google.gson.examples.android.model.LineItem");
    var constructor = lineItemClass.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    var method = lineItemClass.getDeclaredMethod("getPriceInMicros");
    method.setAccessible(true);
    long result = (long) method.invoke(lineItem);

    assertEquals(priceInMicros, result);
  }
}
